#include <stdio.h>
#include <stdlib.h>

// Structure for an adjacency list node
typedef struct AdjListNode {
    int vertex;
    struct AdjListNode* next;
} AdjListNode;

// Structure for a graph
typedef struct Graph {
    int numVertices;
    AdjListNode** adjLists;
} Graph;

// Function to create a new adjacency list node
AdjListNode* createNode(int vertex) {
    AdjListNode* newNode = (AdjListNode*) malloc(sizeof(AdjListNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->vertex = vertex;
    newNode->next = NULL;
    return newNode;
}

// Function to create a graph with given vertices
Graph* createGraph(int vertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    if (!graph) {
        printf("Memory error
");
        return NULL;
    }

    graph->numVertices = vertices;
    graph->adjLists = (AdjListNode**) malloc(vertices * sizeof(AdjListNode*));

    for (int i = 0; i < vertices; i++) {
        graph->adjLists[i] = NULL;
    }

    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    // Add edge from src to dest
    AdjListNode* newNode = createNode(dest);
    if (graph->adjLists[src] == NULL) {
        graph->adjLists[src] = newNode;
    } else {
        AdjListNode* lastNode = graph->adjLists[src];
        while (lastNode->next) {
            lastNode = lastNode->next;
        }
        lastNode->next = newNode;
    }
}

// Function to perform DFS and detect cycle
int isCyclicUtil(Graph* graph, int v, int* visited, int* recStack) {
    if (recStack[v]) return 1;

    if (visited[v]) return 0;

    visited[v] = 1;
    recStack[v] = 1;

    AdjListNode* node = graph->adjLists[v];

    while (node) {
        if (isCyclicUtil(graph, node->vertex, visited, recStack)) return 1;
        node = node->next;
    }

    recStack[v] = 0;
    return 0;
}

// Function to detect cycle in the graph
int isCyclic(Graph* graph) {
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    int* recStack = (int*) malloc(graph->numVertices * sizeof(int));

    for (int node = 0; node < graph->numVertices; node++) {
        visited[node] = 0;
        recStack[node] = 0;
    }

    for (int node = 0; node < graph->numVertices; node++) {
        if (isCyclicUtil(graph, node, visited, recStack)) return 1;
    }

    return 0;
}

int main() {
    int V, E;
    scanf("%d %d", &V, &E);

    Graph* graph = createGraph(V);

    for (int i = 0; i < E; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addEdge(graph, u - 1, v - 1);
        addEdge(graph, v - 1, u - 1);
    }

    if (isCyclic(graph)) {
        printf("Cycle detected\n");
    } else {
        printf("No cycle found\n");
    }

    return 0;
}

